import numpy as np
import sys

# Seed data for scaled_seed_case_main
K, L, N_max = 3, 4, 5
kln = np.arange(K * L * N_max).reshape(K, L, N_max).astype(float)
N_k = np.array([2, 4, 3], dtype=int)

def kln_to_kn(kln, N_k, cleanup=False):
    K, L, N_max = kln.shape

    # Convert N_k to numpy array if list or tuple
    if isinstance(N_k, (list, tuple)):
        N_k = np.array(N_k, dtype=np.int64)
    else:
        N_k = np.asarray(N_k, dtype=np.int64)

    # Validation
    if len(N_k) != K:
        raise ValueError(f"Expected N_k length {K}, got {len(N_k)}")
    if np.any(N_k < 0):
        raise ValueError("N_k values must be non-negative")
    if np.any(N_k > N_max):
        raise ValueError(f"N_k values must not exceed N_max={N_max}")

    total_N = int(np.sum(N_k))
    # Build output array
    kn = np.zeros((L, total_N), dtype=np.float64)
    col = 0
    for k in range(K):
        nk = N_k[k]
        if nk > 0:
            kn[:, col:col+nk] = kln[k, :, :nk]
            col += nk

    # Cleanup: delete the input variable from caller's scope if cleanup=True
    if cleanup:
        frame = sys._getframe(1)
        # Search in local scope first, then global
        for scope in [frame.f_locals, frame.f_globals]:
            for varname, value in list(scope.items()):
                if value is kln:
                    del scope[varname]
                    # Only delete the first occurrence to avoid removing multiple references
                    break

    # Return string representation (matches expected str type)
    return str(kn)
